import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { MapPin, Heart, Trash2, Tag, ChevronRight, ShoppingBag, CheckCircle2, XCircle, Info } from 'lucide-react';
import { useCart } from '../hooks/usecart';
import { useWishlist } from '../hooks/useWishlist';

const CartPage = () => {
  const navigate = useNavigate();
  const { items = [], removeItem, changeQuantity } = useCart();
  const wishlist = useWishlist() || {};

  const [pincode, setPincode] = useState('');
  const [pinStatus, setPinStatus] = useState(null);
  const [couponCode, setCouponCode] = useState('SUMMER26');
  const [isCouponApplied, setIsCouponApplied] = useState(false);

  const [toast, setToast] = useState({ show: false, message: '', type: 'heart' });
  const toastTimer = useRef(null);

  const showToast = (message, type = 'heart') => {
    if (toastTimer.current) clearTimeout(toastTimer.current);
    setToast({ show: true, message, type });
    toastTimer.current = setTimeout(() => {
      setToast(prev => ({ ...prev, show: false }));
    }, 3000);
  };

  useEffect(() => {
    return () => { if (toastTimer.current) clearTimeout(toastTimer.current); };
  }, []);

  const handleCheckPincode = () => {
    if (!pincode) {
      setPinStatus({ type: 'error', message: 'Please enter a pincode.' });
      return false;
    }
    const isHyderabad = /^(500|501|502)\d{3}$/.test(pincode.trim());
    if (isHyderabad) {
      setPinStatus({ type: 'success', message: 'Delivery available in your area!' });
      return true;
    } else {
      setPinStatus({ type: 'error', message: 'Delivery currently limited to Hyderabad.' });
      return false;
    }
  };

  const handleProceedToCheckout = () => {
    const isValid = handleCheckPincode();
    if (isValid) {
      navigate('/checkout');
    } else {
      showToast("Delivery unavailable. Please enter a valid pincode.", 'error');
    }
  };

  const handleSaveForLater = (item) => {
    if (wishlist.addItem) wishlist.addItem(item.productId, item.variantId, item.name, item.price, item.image);
    else if (wishlist.toggleItem) wishlist.toggleItem(item);
    removeItem(item.productId, item.variantId);
    showToast(`Moved ${item.name || 'item'} to your Wishlist`, 'heart');
    window.dispatchEvent(new Event('wishlist-state-change'));
  };

  const validItems = items.filter(item => item && item.productId && String(item.productId) !== 'undefined');

  useEffect(() => {
    if (items.length > 0 && validItems.length === 0) {
      localStorage.removeItem('cart');
      window.location.reload();
    }
  }, [items.length, validItems.length]);

  const totalItems = validItems.reduce((acc, item) => acc + (Number(item.quantity) || 1), 0);

  let totalDiscountedPrice = 0;
  let totalMrp = 0;

  validItems.forEach(item => {
    const qty = Number(item.quantity) || 1;
    const price = Number(item.price) || 0;
    const mrp = Number(item.compare_price || item.mrp) || Math.round(price * 1.25);
    totalDiscountedPrice += (price * qty);
    totalMrp += (mrp * qty);
  });

  const baseDiscount = Math.max(0, totalMrp - totalDiscountedPrice);
  const couponDiscount = isCouponApplied && validItems.length > 0 ? Math.min(10750, totalDiscountedPrice) : 0;

  const finalPayable = Math.max(0, totalDiscountedPrice - couponDiscount);
  const totalSavings = baseDiscount + couponDiscount;

  if (validItems.length === 0) {
    return (
      <div className="bg-gray-50 min-h-[70vh] flex flex-col items-center justify-center px-4 py-16 overflow-x-hidden w-full">
        <div className="bg-white p-8 md:p-12 rounded-2xl shadow-sm border border-gray-100 text-center max-w-lg w-full">
          <div className="w-20 h-20 md:w-24 md:h-24 bg-orange-50 rounded-full flex items-center justify-center mx-auto mb-6">
            <ShoppingBag size={36} className="text-[#f97316]" />
          </div>
          <h2 className="text-xl md:text-2xl font-bold text-gray-900 mb-3 tracking-tight">Your cart is empty</h2>
          <p className="text-sm md:text-base text-gray-500 mb-8">Looks like you haven't added any premium furniture to your cart yet.</p>

          <div className="flex flex-col gap-3">
            <Link to="/" className="inline-block bg-[#f97316] text-white px-8 py-3.5 rounded-xl font-bold hover:bg-black transition-all duration-300 w-full tracking-wide shadow-md hover:shadow-black/20 !outline-none focus:!outline-none border-none shadow-none select-none">
              START SHOPPING
            </Link>
            <Link to="/wishlist" className="inline-flex items-center justify-center gap-2 bg-gray-50 text-gray-600 border border-gray-200 px-8 py-3.5 rounded-xl font-bold hover:bg-orange-50 hover:text-orange-500 hover:border-orange-200 transition-all duration-300 w-full tracking-wide active:scale-[0.98] !outline-none focus:!outline-none border-none shadow-none select-none">
              <Heart size={18} /> GO TO WISHLIST
            </Link>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-[#f4f5f7] min-h-screen py-6 md:py-8 font-sans relative overflow-x-hidden w-full">
      <div className={`fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] transition-all duration-500 ease-out pointer-events-none flex justify-center ${toast.show ? 'opacity-100 scale-100' : 'opacity-0 scale-95'}`}>
        <div className="bg-white/95 backdrop-blur-xl border border-gray-100 shadow-[0_10px_40px_-10px_rgba(0,0,0,0.15)] text-gray-800 px-6 py-3.5 rounded-2xl flex items-center gap-3.5 w-max max-w-[90vw]">
          {toast.type === 'heart' ? <Heart size={20} className="text-orange-500 fill-orange-500 shrink-0 drop-shadow-sm" /> : <Info size={20} className="text-red-500 shrink-0 drop-shadow-sm" />}
          <span className="text-[13px] md:text-sm font-semibold tracking-tight">{toast.message}</span>
        </div>
      </div>

      <div className="container mx-auto px-4 max-w-6xl">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-start">
          <div className="lg:col-span-8 flex flex-col gap-4">
            <div className="bg-white shadow-sm rounded-2xl overflow-hidden border border-gray-100">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center p-4 md:p-5 border-b border-gray-100 gap-4 md:gap-0">
                <div className="flex items-center gap-4 w-full md:w-auto justify-between md:justify-start">
                  <h1 className="text-lg md:text-xl font-bold text-gray-900">My Cart ({totalItems})</h1>
                  <Link to="/wishlist" className="flex items-center justify-center gap-1.5 text-gray-500 hover:text-orange-500 bg-gray-50 hover:bg-orange-50 px-3 py-1.5 rounded-lg border border-gray-100 hover:border-orange-100 transition-all !outline-none focus:!outline-none border-none shadow-none select-none" title="View Wishlist"><Heart size={18} /><span className="text-xs font-bold tracking-wide uppercase hidden sm:block">Wishlist</span></Link>
                </div>

                <div className="flex flex-col items-start md:items-end gap-1 w-full md:w-auto">
                  <div className="flex flex-col sm:flex-row items-start sm:items-center gap-2 sm:gap-3 w-full md:w-auto">
                    <div className="flex items-center text-gray-600 shrink-0"><MapPin size={18} className="mr-1" /><span className="text-sm font-medium">Deliver To</span></div>
                    <div className={`flex items-center border rounded-lg overflow-hidden w-full sm:w-auto transition-all duration-300 bg-white ${pinStatus?.type === 'error' ? 'border-red-300' : pinStatus?.type === 'success' ? 'border-green-300' : 'border-gray-300 focus-within:border-orange-400'}`}>
                      <input type="text" placeholder="Enter Pincode" value={pincode} maxLength={6} onChange={(e) => { setPincode(e.target.value); if (pinStatus) setPinStatus(null); }} className={`w-full sm:w-36 px-3 py-2 text-sm !outline-none border-none !shadow-none !ring-0 ${pinStatus?.type === 'error' ? 'bg-red-50' : 'bg-transparent'}`} />
                      <button onClick={handleCheckPincode} className="bg-transparent text-[#f97316] font-bold text-xs tracking-wide px-4 py-2 border-l border-gray-200 hover:bg-orange-50 active:bg-orange-100 transition-colors duration-200 !outline-none focus:!outline-none border-none shadow-none shrink-0 select-none">CHECK</button>
                    </div>
                  </div>
                  {pinStatus && <div className={`flex items-center gap-1 text-[11px] font-medium mt-1 ${pinStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>{pinStatus.type === 'success' ? <CheckCircle2 size={12} /> : <XCircle size={12} />} {pinStatus.message}</div>}
                </div>
              </div>

              <div className="flex flex-col">
                {validItems.map((item, index) => {
                  const price = Number(item.price) || 0;
                  const mrp = Number(item.compare_price || item.mrp) || Math.round(price * 1.25);
                  const discountPercent = mrp > price && price > 0 ? Math.round(((mrp - price) / mrp) * 100) : 0;
                  const qty = Number(item.quantity) || 1;

                  return (
                    <div key={index} className="group flex flex-col sm:flex-row p-4 sm:p-5 border-b border-gray-100 last:border-0 hover:bg-gray-50/80 transition-colors">
                      <div className="shrink-0 mb-4 sm:mb-0 overflow-hidden rounded-xl border border-gray-200 bg-gray-100 w-full sm:w-32 h-48 sm:h-32">
                        <img src={item.image || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=800&q=80'} alt="Product" className="w-full h-full object-cover transform transition-transform duration-500 ease-out group-hover:scale-[1.04]" />
                      </div>
                      <div className="sm:ml-6 flex-1 flex flex-col justify-between">
                        <div>
                          <h3 className="text-base font-semibold text-gray-900 tracking-tight leading-snug group-hover:text-[#f97316] transition-colors">{item.name}</h3>
                          <p className="text-xs text-gray-500 mt-1 font-medium">Variant: {String(item.variantId || '').replace('var_', '')}</p>
                          <div className="mt-4 flex flex-wrap items-center gap-x-6 gap-y-4">
                            <div className="flex items-center">
                              <span className="text-sm font-medium text-gray-700 mr-3 hidden sm:inline-block">Qty.</span>
                              <div className="flex items-center border border-gray-300 rounded-lg bg-white overflow-hidden">
                                <button onClick={() => { if (qty > 1) changeQuantity(item.productId, item.variantId, qty - 1) }} className="w-8 h-8 flex items-center justify-center text-gray-600 hover:bg-orange-50 hover:text-[#f97316] !outline-none focus:!outline-none border-none bg-transparent select-none">-</button>
                                <span className="w-10 h-8 flex items-center justify-center text-sm font-semibold border-x border-gray-200">{qty}</span>
                                <button onClick={() => changeQuantity(item.productId, item.variantId, qty + 1)} className="w-8 h-8 flex items-center justify-center text-gray-600 hover:bg-orange-50 hover:text-[#f97316] !outline-none focus:!outline-none border-none bg-transparent select-none">+</button>
                              </div>
                            </div>
                            <div className="flex flex-col">
                              {discountPercent > 0 && <span className="text-[10px] sm:text-[11px] font-semibold tracking-wide text-[#22c55e] mb-0.5">Limited-Time Deal</span>}
                              <div className="flex items-baseline gap-2">
                                <span className="text-lg font-bold text-gray-900">₹{(price * qty).toLocaleString('en-IN')}</span>
                                {mrp > price && <span className="text-xs sm:text-sm text-gray-400 line-through font-medium">₹{(mrp * qty).toLocaleString('en-IN')}</span>}
                              </div>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center justify-between sm:justify-start gap-6 mt-5 pt-4 border-t border-gray-100 sm:border-0 sm:pt-0 sm:mt-auto text-sm font-semibold text-gray-500">
                          <button onClick={() => handleSaveForLater(item)} className="flex items-center gap-1.5 hover:text-[#f97316] !outline-none focus:!outline-none border-none bg-transparent select-none"><Heart size={16} /> Save For Later</button>
                          <button onClick={() => removeItem(item.productId, item.variantId)} className="flex items-center gap-1.5 hover:text-red-500 !outline-none focus:!outline-none border-none bg-transparent"><Trash2 size={16} /> Remove</button>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          <div className="lg:col-span-4 flex flex-col gap-4 md:sticky md:top-28">
            <div className="bg-white shadow-sm rounded-2xl p-4 md:p-5 border border-gray-100">
              <div className="flex items-center justify-between cursor-pointer group">
                <div className="flex items-center gap-2"><Tag size={18} className="text-[#f97316]" /><span className="text-sm font-medium text-gray-800"><span className="font-bold text-[#f97316]">LOGIN</span> to unlock coupons!</span></div>
                <ChevronRight size={18} className="text-gray-400" />
              </div>
            </div>

            <div className="bg-white shadow-sm rounded-2xl border border-gray-200 flex flex-col overflow-hidden">
              <div className="p-4 md:p-5 border-b border-gray-100"><h3 className="text-base font-semibold text-gray-800">Price Detail <span className="font-normal text-gray-500 text-sm">({totalItems} Items)</span></h3></div>
              <div className="p-4 md:p-5 space-y-4">
                <div className="flex justify-between items-center text-sm font-medium text-gray-700"><span>MRP</span><span>₹{totalMrp.toLocaleString('en-IN')}</span></div>
                <div className="flex justify-between items-center text-sm font-medium text-gray-700"><span>Discount</span><span className="text-[#22c55e]">- ₹{baseDiscount.toLocaleString('en-IN')}</span></div>
              </div>
              <div className="px-4 md:px-5 py-4 md:py-5 border-t border-gray-100 border-dashed bg-gray-50/50">
                <div className="flex justify-between items-start"><span className="text-base font-semibold text-gray-900">Total Payable</span><div className="flex flex-col items-end"><span className="text-lg md:text-xl font-bold text-gray-900">₹{finalPayable.toLocaleString('en-IN')}</span><span className="text-[10px] text-gray-500 mt-1">Inclusive of all taxes</span></div></div>
              </div>
            </div>

            <div className="mt-2 flex flex-col gap-3">
              <button onClick={handleProceedToCheckout} className="w-full bg-[#e87831] text-white py-4 rounded-lg font-bold tracking-wider hover:bg-[#cf6627] active:scale-[0.98] transition-all duration-300 shadow-[0_4px_14px_rgba(232,120,49,0.35)] hover:shadow-[0_6px_18px_rgba(232,120,49,0.5)] !outline-none focus:!outline-none focus:!ring-0 border-none select-none text-[15px]">PLACE ORDER</button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CartPage;
